from typing import List

class Solution:
    def __init__(self):
        self.k = 0

    def push(self, arr: List[int], k: int, n: int) -> int:
        if n <= k:
            return k
        k = n
        return arr[-1]

    def pop(self) -> int:
        self.k -= 1
        return arr[-1]

    def size(self) -> int:
        return self.k


if __name__ == '__main__':
    arr = list(map(int, input().split()))
    n = int(input())
    s = Solution()
    print(s.push(arr, 0, n))

